@@ -0,0 +1,142 @@
+/**
+ * Message Signal Example
+ *
+ * Demonstrates a lightweight "model -> extension" signaling pattern:
+ * - /start injects a hidden custom message with protocol instructions
+ * - Model emits specific marker strings in assistant messages
+ * - Extension listens on message_end and reacts (show/hide UI)
+ *
+ * Usage:
+ *   /start          Enable protocol for this session
+ *   /stop           Disable protocol and clear UI
+ *   /signal-help    Show marker strings
+ */
+
+import type { ExtensionAPI, ExtensionContext } from "@mariozechner/pi-coding-agent";
+
+const PROTOCOL_TYPE = "message-signal-protocol";
+const OPEN_SIGNAL = "[[PI_SIGNAL_OPEN_UI]]";
+const CLOSE_SIGNAL = "[[PI_SIGNAL_CLOSE_UI]]";
+const DONE_SIGNAL = "[[PI_SIGNAL_DONE]]";
+
+const PROTOCOL_INSTRUCTIONS = `
+You are in extension signaling mode.
+
+When you want the extension to open UI, output this marker on its own line:
+${OPEN_SIGNAL}
+
+When you want the extension to close UI, output this marker on its own line:
+${CLOSE_SIGNAL}
+
+When your task is complete, output this marker on its own line:
+${DONE_SIGNAL}
+
+Rules:
+- Keep normal helpful text.
+- Emit markers only when needed.
+- Emit exact marker text, no typos.
+`;
+
+function extractAssistantText(message: unknown): string {
+	if (!message || typeof message !== "object") return "";
+	const role = (message as { role?: unknown }).role;
+	if (role !== "assistant") return "";
+
+	const content = (message as { content?: unknown }).content;
+	if (!Array.isArray(content)) return "";
+
+	return content
+		.map((part) => {
+			if (!part || typeof part !== "object") return "";
+			if ((part as { type?: unknown }).type !== "text") return "";
+			const text = (part as { text?: unknown }).text;
+			return typeof text === "string" ? text : "";
+		})
+		.filter((text) => text.length > 0)
+		.join("\n");
+}
+
+export default function messageSignalExtension(pi: ExtensionAPI) {
+	let enabled = false;
+
+	const showPanel = (ctx: ExtensionContext): void => {
+		ctx.ui.setWidget("message-signal", ["Signal UI is open", `Waiting for ${CLOSE_SIGNAL}`]);
+		ctx.ui.setStatus("message-signal", "signal-ui: open");
+	};
+
+	const hidePanel = (ctx: ExtensionContext): void => {
+		ctx.ui.setWidget("message-signal", undefined);
+		ctx.ui.setStatus("message-signal", undefined);
+	};
+
+	pi.registerCommand("start", {
+		description: "Enable message signaling protocol for model -> extension events",
+		handler: async (_args, ctx) => {
+			enabled = true;
+
+			if (ctx.isIdle()) {
+				pi.sendMessage({
+					customType: PROTOCOL_TYPE,
+					content: PROTOCOL_INSTRUCTIONS,
+					display: false,
+					details: {
+						enabledAt: Date.now(),
+						signals: { open: OPEN_SIGNAL, close: CLOSE_SIGNAL, done: DONE_SIGNAL },
+					},
+				});
+			} else {
+				pi.sendMessage(
+					{
+						customType: PROTOCOL_TYPE,
+						content: PROTOCOL_INSTRUCTIONS,
+						display: false,
+						details: {
+							enabledAt: Date.now(),
+							signals: { open: OPEN_SIGNAL, close: CLOSE_SIGNAL, done: DONE_SIGNAL },
+						},
+					},
+					{ deliverAs: "followUp" },
+				);
+			}
+
+			ctx.ui.notify("Message signaling enabled", "info");
+			ctx.ui.setStatus("message-signal", "signal-mode: enabled");
+		},
+	});
+
+	pi.registerCommand("stop", {
+		description: "Disable message signaling protocol and clear extension UI",
+		handler: async (_args, ctx) => {
+			enabled = false;
+			hidePanel(ctx);
+			ctx.ui.notify("Message signaling disabled", "info");
+		},
+	});
+
+	pi.registerCommand("signal-help", {
+		description: "Show marker strings used by message signaling",
+		handler: async (_args, ctx) => {
+			ctx.ui.notify(`open=${OPEN_SIGNAL} close=${CLOSE_SIGNAL} done=${DONE_SIGNAL}`, "info");
+		},
+	});
+
+	pi.on("message_end", async (event, ctx) => {
+		if (!enabled) return;
+
+		const text = extractAssistantText(event.message);
+		if (!text) return;
+
+		if (text.includes(OPEN_SIGNAL)) {
+			showPanel(ctx);
+			ctx.ui.notify("Received OPEN signal", "info");
+		}
+		if (text.includes(CLOSE_SIGNAL)) {
+			hidePanel(ctx);
+			ctx.ui.notify("Received CLOSE signal", "info");
+		}
+		if (text.includes(DONE_SIGNAL)) {
+			ctx.ui.notify("Received DONE signal", "info");
+			ctx.ui.setStatus("message-signal", "signal-mode: done");
+		}
+	});
+}
